BEGIN
  p_QueryID_09d8217f := '3366D42B-C3A1-4CE0-9F40-7FBE15F2EA57';
  p_SQLDialectID_09d8217f := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_09d8217f := '-- PostgreSQL variant for External Change Detection - Detect Creations
SELECT 
    {{ ColumnList }}, ot."{{ CreatedAtField }}" AS "CreatedAt", ot."{{ UpdatedAtField }}" AS "UpdatedAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
LEFT JOIN 
    [__mj].vwRecordChanges rc 
    ON 
    ({{ PrimaryKeyJoin }} = rc."RecordID") AND 
    rc."Type" = ''Create'' AND 
    rc."EntityID" = {{ EntityID | sqlString }} 
WHERE 
    rc."RecordID" IS NULL;
';
  p_ID_09d8217f := 'D85DE0AD-5B5B-4EF4-82BC-C634CE39E836';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_09d8217f, p_SQLDialectID := p_SQLDialectID_09d8217f, p_SQL := p_SQL_09d8217f, p_ID := p_ID_09d8217f);
END $$;

-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_QueryID_75e77c86 UUID;
  p_SQLDialectID_75e77c86 UUID;
  p_SQL_75e77c86 TEXT;
  p_ID_75e77c86 UUID;
BEGIN
  p_QueryID_75e77c86 := '46A91235-2122-40E8-9289-20D04489CAC5';
  p_SQLDialectID_75e77c86 := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_75e77c86 := '-- PostgreSQL variant for External Change Detection - Detect Updates
SELECT 
    {{ ColumnList }}, ot."{{ UpdatedAtField }}" AS "UpdatedAt", rc.last_change_time AS "LatestRecordChangeAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
INNER JOIN (
    SELECT 
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM 
        [__mj].vwRecordChanges
    WHERE 
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY 
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc."RecordID"
WHERE 
    ot."{{ UpdatedAtField }}" > COALESCE(rc.last_change_time, CAST(''1900-01-01 00:00:00.000'' AS TIMESTAMPTZ));
';
  p_ID_75e77c86 := '565C5AF3-5F59-4531-B21D-53EBC884EF5B';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_75e77c86, p_SQLDialectID := p_SQLDialectID_75e77c86, p_SQL := p_SQL_75e77c86, p_ID := p_ID_75e77c86);
END $$;

-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_QueryID_ddfef1d7 UUID;
  p_SQLDialectID_ddfef1d7 UUID;
  p_SQL_ddfef1d7 TEXT;
  p_ID_ddfef1d7 UUID;
BEGIN
  p_QueryID_ddfef1d7 := '028A39F6-2B38-4ED1-8235-4671B7CD330B';
  p_SQLDialectID_ddfef1d7 := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_ddfef1d7 := '-- PostgreSQL variant for External Change Detection - Detect Deletions
-- TECHNICAL DEBT: Joining on dynamically generated PrimaryKeyJoin (a concatenated string) prevents
-- the use of indexes on the organic table (ot). For massive tables, this will result in a table scan.
-- A future schema change to separate RecordID parts into native columns is recommended.
SELECT 
    rc."RecordID", MAX(rc."ChangedAt") AS "ChangedAt"
FROM 
    [__mj].vwRecordChanges rc
LEFT JOIN 
    "{{ SchemaName }}"."{{ BaseView }}" ot 
    ON 
    rc."RecordID" = {{ PrimaryKeyJoin }}
WHERE 
    {{ PrimaryKeyIsNull }}
    AND 
        rc."EntityID" = {{ EntityID | sqlString }} 
    AND 
        rc."Type" <> ''Delete''
GROUP BY 
    rc."RecordID"
HAVING 
    MAX(CASE WHEN rc."Type" = ''Delete'' THEN 1 ELSE 0
END) = 0;
';
  p_ID_ddfef1d7 := 'F325DCBE-347F-4F59-9A8A-A18706803C8B';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_ddfef1d7, p_SQLDialectID := p_SQLDialectID_ddfef1d7, p_SQL := p_SQL_ddfef1d7, p_ID := p_ID_ddfef1d7);
END $$;

